const lead = $input.first().json;

// Qualify lead score
let score = 0;
if (lead.country && ['SN', 'CI', 'CM'].includes(lead.country)) score += 30;
if (lead.businessType === 'reseller') score += 25;
if (lead.budget > 1000) score += 20;
if (lead.interest === 'wholesale') score += 25;

const qualification = score >= 50 ? 'hot' : score >= 30 ? 'warm' : 'cold';
const nextAction = qualification === 'hot' ? 'direct_to_sales' : 'nurture_sequence';

return [{json: {...lead, score, qualification, nextAction, agent: 'sales'}}];
